package qrspicmd

import (
	"bufio"
	"bytes"
	"crypto/sha256"
	"encoding/hex"
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"path/filepath"
	"strings"
)

type sessionEntry struct {
	Type      string          `json:"type"`
	ID        string          `json:"id,omitempty"`
	Cwd       string          `json:"cwd,omitempty"`
	Timestamp string          `json:"timestamp,omitempty"`
	Message   *sessionMessage `json:"message,omitempty"`
}

type sessionMessage struct {
	Role         string          `json:"role"`
	Content      json.RawMessage `json:"content"`
	StopReason   string          `json:"stopReason,omitempty"`
	ErrorMessage string          `json:"errorMessage,omitempty"`
}

type AssistantTerminalEvidence struct {
	SessionPath        string `json:"sessionPath,omitempty"`
	SessionID          string `json:"sessionId,omitempty"`
	Line               int    `json:"line,omitempty"`
	Timestamp          string `json:"timestamp,omitempty"`
	StopReason         string `json:"stopReason,omitempty"`
	ErrorMessage       string `json:"errorMessage,omitempty"`
	ContextWindowError bool   `json:"contextWindowError,omitempty"`
	EvidenceID         string `json:"evidenceId,omitempty"`
}

type sessionContentBlock struct {
	Type string `json:"type"`
	Text string `json:"text,omitempty"`
}

func ResolveSessionPath(sessionDir, sessionID, cwd string) (string, error) {
	if strings.TrimSpace(sessionDir) == "" || strings.TrimSpace(sessionID) == "" {
		return "", errors.New("session dir and session id are required")
	}

	if _, err := os.Stat(sessionDir); err != nil {
		if os.IsNotExist(err) {
			return "", fmt.Errorf("session %q not found in %s", sessionID, sessionDir)
		}
		return "", err
	}

	var matches []string
	walkErr := filepath.WalkDir(
		sessionDir,
		func(path string, entry os.DirEntry, err error) error {
			if err != nil {
				return err
			}
			if entry.IsDir() || filepath.Ext(entry.Name()) != ".jsonl" {
				return nil
			}
			header, err := readSessionHeader(path)
			if err != nil {
				return nil
			}
			if header.Type == "session" && header.ID == sessionID &&
				(strings.TrimSpace(cwd) == "" || header.Cwd == cwd) {
				matches = append(matches, path)
			}
			return nil
		},
	)
	if walkErr != nil {
		return "", walkErr
	}

	switch len(matches) {
	case 1:
		return matches[0], nil
	case 0:
		return "", fmt.Errorf("session %q not found in %s", sessionID, sessionDir)
	default:
		return "", fmt.Errorf(
			"session %q matched multiple files in %s",
			sessionID,
			sessionDir,
		)
	}
}

func readSessionHeader(path string) (sessionEntry, error) {
	file, err := os.Open(path)
	if err != nil {
		return sessionEntry{}, err
	}
	defer file.Close()

	scanner := bufio.NewScanner(file)
	scanner.Buffer(make([]byte, 64*1024), 1024*1024)
	if !scanner.Scan() {
		if err := scanner.Err(); err != nil {
			return sessionEntry{}, err
		}
		return sessionEntry{}, errors.New("empty session file")
	}
	var header sessionEntry
	if err := json.Unmarshal(bytes.TrimSpace(scanner.Bytes()), &header); err != nil {
		return sessionEntry{}, err
	}
	return header, nil
}

func LatestAssistantTerminalEvidence(
	path string,
) (AssistantTerminalEvidence, bool, error) {
	file, err := os.Open(path)
	if err != nil {
		return AssistantTerminalEvidence{}, false, err
	}
	defer file.Close()

	sessionID := ""
	var latest AssistantTerminalEvidence
	found := false
	scanner := bufio.NewScanner(file)
	scanner.Buffer(make([]byte, 64*1024), 1024*1024)
	lineNo := 0
	for scanner.Scan() {
		lineNo++
		line := bytes.TrimSpace(scanner.Bytes())
		if len(line) == 0 {
			continue
		}
		var entry sessionEntry
		if err := json.Unmarshal(line, &entry); err != nil {
			continue
		}
		if entry.Type == "session" && strings.TrimSpace(entry.ID) != "" {
			sessionID = entry.ID
			continue
		}
		if entry.Type != "message" || entry.Message == nil ||
			entry.Message.Role != "assistant" {
			continue
		}
		if strings.TrimSpace(entry.Message.StopReason) == "" &&
			strings.TrimSpace(entry.Message.ErrorMessage) == "" {
			continue
		}
		evidence := AssistantTerminalEvidence{
			SessionPath:  path,
			SessionID:    sessionID,
			Line:         lineNo,
			Timestamp:    entry.Timestamp,
			StopReason:   entry.Message.StopReason,
			ErrorMessage: entry.Message.ErrorMessage,
		}
		evidence.ContextWindowError = strings.EqualFold(evidence.StopReason, "error") &&
			IsContextWindowErrorMessage(evidence.ErrorMessage)
		evidence.EvidenceID = terminalEvidenceID(evidence)
		latest = evidence
		found = true
	}
	if err := scanner.Err(); err != nil {
		return AssistantTerminalEvidence{}, false, err
	}
	return latest, found, nil
}

func IsContextWindowErrorMessage(message string) bool {
	text := strings.ToLower(message)
	needles := []string{
		"context window",
		"context length",
		"context_length_exceeded",
		"maximum context",
		"context limit",
		"input exceeds",
	}
	for _, needle := range needles {
		if strings.Contains(text, needle) {
			return true
		}
	}
	return false
}

func terminalEvidenceID(e AssistantTerminalEvidence) string {
	raw := strings.Join([]string{
		strings.TrimSpace(e.SessionID),
		filepath.Clean(strings.TrimSpace(e.SessionPath)),
		fmt.Sprintf("%d", e.Line),
		strings.TrimSpace(e.Timestamp),
		strings.TrimSpace(e.StopReason),
		strings.TrimSpace(e.ErrorMessage),
	}, "\x00")
	sum := sha256.Sum256([]byte(raw))
	return hex.EncodeToString(sum[:])[:16]
}

func ExtractFinalAssistantTextFromSession(path string) (string, error) {
	last, err := extractLastAssistantTextFromSession(path, true)
	if err != nil {
		return "", err
	}
	if last == "" {
		return "", fmt.Errorf(
			"session %s has no assistant text containing qrspi_result",
			path,
		)
	}
	return last, nil
}

func ExtractLastAssistantTextFromSession(path string) (string, error) {
	last, err := extractLastAssistantTextFromSession(path, false)
	if err != nil {
		return "", err
	}
	if last == "" {
		return "", fmt.Errorf("session %s has no assistant text", path)
	}
	return last, nil
}

func extractLastAssistantTextFromSession(
	path string,
	requireQRSPIResult bool,
) (string, error) {
	file, err := os.Open(path)
	if err != nil {
		return "", err
	}
	defer file.Close()

	var last string
	scanner := bufio.NewScanner(file)
	scanner.Buffer(make([]byte, 64*1024), 1024*1024)
	for scanner.Scan() {
		line := bytes.TrimSpace(scanner.Bytes())
		if len(line) == 0 {
			continue
		}
		var entry sessionEntry
		if err := json.Unmarshal(line, &entry); err != nil {
			continue
		}
		if entry.Type != "message" || entry.Message == nil ||
			entry.Message.Role != "assistant" {
			continue
		}
		if requireQRSPIResult &&
			(entry.Message.StopReason == "error" || entry.Message.StopReason == "aborted") {
			continue
		}
		text := textBlocksFromAssistantMessage(*entry.Message)
		if strings.TrimSpace(text) == "" {
			continue
		}
		if !requireQRSPIResult || strings.Contains(text, "qrspi_result") {
			last = text
		}
	}
	if err := scanner.Err(); err != nil {
		return "", err
	}
	return last, nil
}

func textBlocksFromAssistantMessage(msg sessionMessage) string {
	var blocks []sessionContentBlock
	if err := json.Unmarshal(msg.Content, &blocks); err == nil {
		var parts []string
		for _, block := range blocks {
			if block.Type == "text" && block.Text != "" {
				parts = append(parts, block.Text)
			}
		}
		return strings.Join(parts, "\n")
	}

	var text string
	if err := json.Unmarshal(msg.Content, &text); err == nil {
		return text
	}
	return ""
}

package qrspicmd

import (
	"context"
	"fmt"
	"os"
	"strings"
)

func InspectActiveChildHealth(
	ctx context.Context,
	state ManagerState,
	stateFile string,
	d deps,
) (ActiveChildHealth, error) {
	if state.ActiveChild == nil {
		return ActiveChildHealth{
			Status:   ActiveChildUnknown,
			Evidence: []string{"no active child"},
		}, nil
	}
	child := state.ActiveChild
	health := ActiveChildHealth{
		Status:      ActiveChildUnknown,
		ChildID:     child.ID,
		Stage:       child.Stage,
		PaneID:      child.TmuxPaneID,
		OutputPath:  child.OutputPath,
		StatusPath:  child.StatusPath,
		DonePath:    child.DonePath,
		SessionDir:  child.SessionDir,
		SessionPath: child.SessionPath,
		SafeCommand: fmt.Sprintf(
			"vamos qrspi repair-state --state-file %s --clear-failed-child --relaunch",
			stateFile,
		),
	}

	status, _ := ReadChildStatus(child.StatusPath)
	if status != nil {
		health.ExitCode = &status.ExitCode
		health.Evidence = append(
			health.Evidence,
			fmt.Sprintf("exitCode: %d", status.ExitCode),
		)
	}
	if data, err := os.ReadFile(child.OutputPath); err == nil {
		health.OutputTail = FilterChildOutputTail(data, 8)
	}

	if strings.TrimSpace(health.SessionPath) == "" {
		if resolved, err := resolveActiveChildSessionPath(child); err == nil {
			health.SessionPath = resolved
		}
	}
	if strings.TrimSpace(health.SessionPath) != "" {
		if evidence, ok, err := LatestAssistantTerminalEvidence(
			health.SessionPath,
		); err == nil && ok &&
			evidence.ContextWindowError {
			health.Status = ActiveChildProviderContextError
			health.TerminalEvidence = &evidence
			health.Evidence = append(
				health.Evidence,
				providerContextEvidenceLines(evidence)...)
			health.SafeCommand = providerContextRecoverySafeCommand(stateFile)
			return health, nil
		}
	}

	hasResult, sessionPath, resultErr := ChildHasQRSPIResult(state)
	if hasResult {
		health.Status = ActiveChildFinishedNeedsValidation
		health.SessionPath = sessionPath
		health.Evidence = append(health.Evidence, "session has qrspi_result")
		return health, nil
	}
	if strings.TrimSpace(sessionPath) != "" {
		health.SessionPath = sessionPath
	}
	sessionText := ""
	if strings.TrimSpace(health.SessionPath) != "" {
		if text, err := ExtractLastAssistantTextFromSession(
			health.SessionPath,
		); err == nil {
			sessionText = text
		}
	}

	paneOK := false
	if strings.TrimSpace(child.TmuxPaneID) != "" {
		ok, err := tmuxClient(d).PaneExists(ctx, TmuxPane{ID: child.TmuxPaneID})
		paneOK = ok && err == nil
		if !paneOK {
			health.Evidence = append(health.Evidence, "pane missing")
		}
	}
	if status != nil && HasDoneMarker(child.DonePath) && !hasResult &&
		HasChildContextExhaustionEvidence(health, sessionText) {
		health.Status = ActiveChildContextExhausted
		if resultErr != nil {
			health.Evidence = append(health.Evidence, resultErr.Error())
		}
		if strings.TrimSpace(sessionText) != "" {
			health.Evidence = append(
				health.Evidence,
				"session has context-limit/no-result evidence",
			)
		}
		health.SafeCommand = fmt.Sprintf(
			"pi --resume %s # then run /compact only if this is the exhausted child session",
			firstNonEmpty(health.SessionPath, child.SessionID),
		)
		return health, nil
	}
	if status != nil && status.ExitCode != 0 && HasDoneMarker(child.DonePath) &&
		!hasResult {
		health.Status = ActiveChildLaunchFailed
		if resultErr != nil {
			health.Evidence = append(health.Evidence, resultErr.Error())
		}
		return health, nil
	}
	if status != nil && status.ExitCode == 0 && HasDoneMarker(child.DonePath) {
		health.Status = ActiveChildFinishedNeedsValidation
		return health, nil
	}
	if !paneOK && strings.TrimSpace(child.TmuxPaneID) != "" {
		health.Status = ActiveChildPaneMissing
		return health, nil
	}
	health.Status = ActiveChildRunning
	health.Evidence = append(
		health.Evidence,
		"pane exists and no terminal failure status",
	)
	return health, nil
}

func HasDoneMarker(path string) bool {
	if strings.TrimSpace(path) == "" {
		return false
	}
	_, err := os.Stat(path)
	return err == nil
}

func LatestTerminalEvidenceForActiveChild(
	state ManagerState,
) (AssistantTerminalEvidence, bool, error) {
	if state.ActiveChild == nil {
		return AssistantTerminalEvidence{}, false, nil
	}
	path, err := resolveActiveChildSessionPath(state.ActiveChild)
	if err != nil {
		return AssistantTerminalEvidence{}, false, err
	}
	return LatestAssistantTerminalEvidence(path)
}

func ChildHasQRSPIResult(state ManagerState) (bool, string, error) {
	text, parseCtx, err := ReadChildResultText(state, ResultSourceOptions{})
	if err != nil {
		return false, "", err
	}
	return strings.Contains(text, "qrspi_result"), parseCtx.SessionPath, nil
}

func HasChildContextExhaustionEvidence(
	health ActiveChildHealth,
	sessionText string,
) bool {
	lines := append([]string{}, health.Evidence...)
	lines = append(lines, health.OutputTail...)
	if strings.TrimSpace(sessionText) != "" {
		lines = append(lines, sessionText)
	}
	needles := []string{
		"context length",
		"context window",
		"context_length_exceeded",
		"maximum context",
		"context limit",
		"input exceeds",
		"compaction failed",
	}
	for _, line := range lines {
		text := strings.ToLower(line)
		for _, needle := range needles {
			if strings.Contains(text, needle) {
				return true
			}
		}
	}
	return false
}

func resolveActiveChildSessionPath(child *ChildRunRef) (string, error) {
	if child == nil {
		return "", fmt.Errorf("no active child")
	}
	if strings.TrimSpace(child.SessionPath) != "" {
		return strings.TrimSpace(child.SessionPath), nil
	}
	return ResolveSessionPath(child.SessionDir, child.SessionID, child.Cwd)
}

func providerContextEvidenceLines(e AssistantTerminalEvidence) []string {
	lines := []string{
		fmt.Sprintf("provider stopReason: %s", e.StopReason),
		fmt.Sprintf("provider error: %s", e.ErrorMessage),
		fmt.Sprintf("evidence id: %s", e.EvidenceID),
	}
	if e.SessionPath != "" {
		lines = append(lines, fmt.Sprintf("session: %s", e.SessionPath))
	}
	if e.SessionID != "" {
		lines = append(lines, fmt.Sprintf("session id: %s", e.SessionID))
	}
	if e.Line > 0 {
		lines = append(lines, fmt.Sprintf("line: %d", e.Line))
	}
	if e.Timestamp != "" {
		lines = append(lines, fmt.Sprintf("timestamp: %s", e.Timestamp))
	}
	return lines
}

func providerContextRecoverySafeCommand(stateFile string) string {
	return fmt.Sprintf(
		"vamos qrspi inspect --state-file %s --sessions --latest",
		stateFile,
	)
}

func providerContextRecoveryContinueCommand(stateFile string) string {
	return fmt.Sprintf(
		"vamos qrspi recover-manual --state-file %s --mode latest-session --continue",
		stateFile,
	)
}

func providerContextRecoverySummaryCommand(
	stateFile string,
	evidence AssistantTerminalEvidence,
) string {
	if strings.TrimSpace(evidence.SessionPath) == "" {
		return ""
	}
	return fmt.Sprintf(
		"vamos qrspi recover-summary --state-file %s --session-file %s",
		stateFile,
		evidence.SessionPath,
	)
}

func IsTerminalFailedChild(health ActiveChildHealth) bool {
	return health.Status == ActiveChildLaunchFailed
}

func IsTerminalProviderContextError(health ActiveChildHealth) bool {
	return health.Status == ActiveChildProviderContextError ||
		(health.TerminalEvidence != nil && health.TerminalEvidence.ContextWindowError)
}

func IsRecoverableNoResultChild(health ActiveChildHealth) bool {
	return health.Status == ActiveChildContextExhausted ||
		IsTerminalProviderContextError(health)
}

package qrspicmd

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"os"
	"path/filepath"
	"regexp"
	"strings"
	"time"
)

func RunRecoverSummary(
	ctx context.Context,
	opts RecoverSummaryOptions,
	d deps,
	out io.Writer,
) error {
	if strings.TrimSpace(opts.StateFile) == "" {
		return errors.New("state-file is required")
	}
	if strings.TrimSpace(opts.SessionFile) == "" {
		return errors.New("session-file is required")
	}
	out = ensureWriter(out)
	state, err := stateStore(d, "", time.Now).Load(opts.StateFile)
	if err != nil {
		return err
	}
	now := time.Now()
	if d.Clock != nil {
		now = d.Clock()
	}
	stage := strings.TrimSpace(opts.Stage)
	if stage == "" && state.ActiveChild != nil {
		stage = strings.TrimSpace(state.ActiveChild.Stage)
	}
	if stage == "" {
		stage = strings.TrimSpace(string(state.Workflow.CurrentNodeID))
	}
	if stage == "" {
		stage = "unknown"
	}
	childID := "unknown-child"
	if state.ActiveChild != nil && strings.TrimSpace(state.ActiveChild.ID) != "" {
		childID = strings.TrimSpace(state.ActiveChild.ID)
	}
	planDir := resolvedRecoveryPlanDir(state)
	if strings.TrimSpace(planDir) == "" {
		return errors.New("plan directory is required in manager state")
	}
	evidence, _, err := LatestAssistantTerminalEvidence(opts.SessionFile)
	if err != nil {
		return err
	}
	notePath := RecoverySummaryPath(planDir, stage, childID, now)
	promptPath := filepath.Join(
		filepath.Dir(opts.StateFile),
		"prompts",
		fmt.Sprintf("recover-summary-%s.md", timestampForRecoveryFile(now)),
	)
	req := RecoverySummaryRequest{
		StateFile:         opts.StateFile,
		PlanDir:           planDir,
		ImplementationCwd: state.ImplementationCwd,
		Stage:             stage,
		ChildID:           childID,
		SessionFile:       opts.SessionFile,
		Evidence:          evidence,
		LatestArtifact:    latestRecoveryArtifact(state),
		PromptPath:        promptPath,
		NotePath:          notePath,
	}
	if err := WriteRecoverySummaryPrompt(req, promptPath); err != nil {
		return err
	}
	if opts.DryRun {
		if err := writeDryRunRecoveryNote(req, notePath); err != nil {
			return err
		}
	} else {
		binary := strings.TrimSpace(opts.PiBinary)
		if binary == "" {
			binary = "pi"
		}
		result, err := commandRunner(d).Run(ctx, binary, "@"+promptPath)
		if err != nil {
			return fmt.Errorf(
				"run recovery summarizer %q failed: %w; prompt written at %s; rerun with --dry-run to create a placeholder note",
				binary,
				err,
				promptPath,
			)
		}
		if result.ExitCode != 0 {
			return fmt.Errorf(
				"run recovery summarizer %q exited %d: %s; prompt written at %s",
				binary,
				result.ExitCode,
				strings.TrimSpace(result.Stderr),
				promptPath,
			)
		}
	}
	if strings.EqualFold(opts.Output, "json") ||
		strings.EqualFold(opts.Output, "ndjson") {
		return json.NewEncoder(out).Encode(req)
	}
	fmt.Fprintf(out, "recovery prompt: %s\n", promptPath)
	fmt.Fprintf(out, "recovery note: %s\n", notePath)
	fmt.Fprintf(out, "stage: %s\n", stage)
	fmt.Fprintf(out, "session: %s\n", opts.SessionFile)
	if evidence.EvidenceID != "" {
		fmt.Fprintf(out, "evidence id: %s\n", evidence.EvidenceID)
	}
	return nil
}

func WriteRecoverySummaryPrompt(req RecoverySummaryRequest, promptPath string) error {
	if err := os.MkdirAll(filepath.Dir(promptPath), 0o755); err != nil {
		return err
	}
	var b strings.Builder
	b.WriteString("# q-manager recovery summarizer\n\n")
	b.WriteString(
		"You are a read-only recovery summarizer. Do not emit qrspi_result. Do not advance graph. Do not edit code.\n\n",
	)
	b.WriteString("Read:\n")
	b.WriteString("- Failed session: " + req.SessionFile + "\n")
	b.WriteString("- Plan memory: " + filepath.Join(req.PlanDir, "AGENTS.md") + "\n")
	b.WriteString("- Current stage artifacts as needed.\n")
	if strings.TrimSpace(req.LatestArtifact) != "" {
		b.WriteString("- Latest known artifact: " + req.LatestArtifact + "\n")
	}
	b.WriteString("\nWrite exactly: " + req.NotePath + "\n\n")
	b.WriteString("Include:\n")
	b.WriteString("- Last reliable completed work.\n")
	b.WriteString("- Terminal provider error evidence.\n")
	b.WriteString("- Same-stage relaunch instructions.\n")
	b.WriteString("- Commands/artifacts already checked.\n")
	b.WriteString("- Avoid repeating huge outputs blindly.\n\n")
	b.WriteString("Context:\n")
	b.WriteString("- State file: " + req.StateFile + "\n")
	b.WriteString("- Plan dir: " + req.PlanDir + "\n")
	if strings.TrimSpace(req.ImplementationCwd) != "" {
		b.WriteString("- Implementation cwd: " + req.ImplementationCwd + "\n")
	}
	b.WriteString("- Stage: " + req.Stage + "\n")
	b.WriteString("- Child: " + req.ChildID + "\n")
	if req.Evidence.EvidenceID != "" {
		b.WriteString("- Evidence ID: " + req.Evidence.EvidenceID + "\n")
	}
	if req.Evidence.SessionID != "" {
		b.WriteString("- Session ID: " + req.Evidence.SessionID + "\n")
	}
	if req.Evidence.Line > 0 {
		b.WriteString(fmt.Sprintf("- Evidence line: %d\n", req.Evidence.Line))
	}
	if req.Evidence.StopReason != "" {
		b.WriteString("- Stop reason: " + req.Evidence.StopReason + "\n")
	}
	if req.Evidence.ErrorMessage != "" {
		b.WriteString("- Provider error: " + req.Evidence.ErrorMessage + "\n")
	}
	if req.Evidence.ContextWindowError {
		b.WriteString("- Context-window error: true\n")
	}
	return os.WriteFile(promptPath, []byte(b.String()), 0o644)
}

func RecoverySummaryPath(planDir, stage, childID string, now time.Time) string {
	return filepath.Join(
		planDir,
		"context",
		"recovery",
		fmt.Sprintf(
			"%s_%s_%s_context-recovery.md",
			timestampForRecoveryPath(now),
			slugForRecoveryPath(stage),
			slugForRecoveryPath(childID),
		),
	)
}

func writeDryRunRecoveryNote(req RecoverySummaryRequest, notePath string) error {
	if err := os.MkdirAll(filepath.Dir(notePath), 0o755); err != nil {
		return err
	}
	var b strings.Builder
	b.WriteString("---\n")
	b.WriteString("stage: recovery-summary\n")
	b.WriteString("source: recover-summary --dry-run\n")
	b.WriteString("---\n\n")
	b.WriteString("# q-manager child context recovery note\n\n")
	b.WriteString(
		"Same-stage relaunch only. Do not emit qrspi_result. Do not advance graph. Do not edit code from this helper.\n\n",
	)
	b.WriteString("- Stage: " + req.Stage + "\n")
	b.WriteString("- Child: " + req.ChildID + "\n")
	b.WriteString("- Failed session: " + req.SessionFile + "\n")
	if req.Evidence.EvidenceID != "" {
		b.WriteString("- Evidence ID: " + req.Evidence.EvidenceID + "\n")
	}
	if req.Evidence.ErrorMessage != "" {
		b.WriteString("- Provider error: " + req.Evidence.ErrorMessage + "\n")
	}
	if req.LatestArtifact != "" {
		b.WriteString("- Latest known artifact: " + req.LatestArtifact + "\n")
	}
	b.WriteString(
		"\nNext child prompt: read this note, inspect the failed session tail and named artifacts, then relaunch the same graph node with focused context. Avoid repeating huge outputs blindly.\n",
	)
	return os.WriteFile(notePath, []byte(b.String()), 0o644)
}

func resolvedRecoveryPlanDir(state ManagerState) string {
	planDir := strings.TrimSpace(state.CanonicalPlanDir)
	if planDir == "" {
		return ""
	}
	if filepath.IsAbs(planDir) {
		return filepath.Clean(planDir)
	}
	for _, base := range []string{state.SourceCwd, state.ImplementationCwd} {
		if strings.TrimSpace(base) != "" {
			return filepath.Join(base, planDir)
		}
	}
	return filepath.Clean(planDir)
}

func latestRecoveryArtifact(state ManagerState) string {
